import React from 'react';
import {Divider as PrimeDivider} from 'primereact/divider';
import type {IDividerComponent} from '@lmb-it/kitsconcerto-types';
import {ResponsiveElement, useSeparator} from "../../factory";
import {useKitsTheme} from '../../contexts/Theme';

const Divider: React.FC<IDividerComponent> = (props) => {
    const {cssProps, nativeProps} = useSeparator<any>(props);
    const {
        align,
        children,
        layout = 'horizontal',
        type: borderType = 'solid',
        unstyled = false,
        ...rest
    } = nativeProps;

    const {resolveToken} = useKitsTheme();
    const dividerColor = resolveToken('divider');

    const style: React.CSSProperties = {};
    if (!unstyled) {
        style['--surface-border' as any] = dividerColor;
    }

    return (
        <ResponsiveElement
            cssProps={cssProps}
            nativeProps={rest}
            additionalStyles={{}}
        >
            <PrimeDivider
                align={align as any}
                layout={layout}
                type={borderType}
                unstyled={unstyled}
                style={style}
            >
                {children}
            </PrimeDivider>
        </ResponsiveElement>
    );
};

export default Divider;
